svg.script:
(function(){
  var edges = [{id:"p0",len:117},{id:"p1",len:141},{id:"p2",len:114},{id:"p3",len:74},{id:"p4",len:146},{id:"p5",len:114},{id:"p6",len:95},{id:"p7",len:193},{id:"p8",len:232},{id:"p9",len:184},{id:"p10",len:114},{id:"p11",len:119},{id:"p12",len:148},{id:"p13",len:148},{id:"p14",len:103},{id:"p15",len:157},{id:"p16",len:202},{id:"p17",len:248},{id:"p18",len:184},{id:"p19",len:301},{id:"p20",len:141},{id:"p21",len:175}];

  // Active pulses: each has its own path clone flying along
  // We use stroke-dashoffset animation via requestAnimationFrame

  // For each edge: randomly pick direction + speed + start offset
  // Multiple simultaneous pulses per edge possible
  var pulses = []; // {el, len, dir, pos, speed, opacity}

  function rand(a,b){ return a + Math.random()*(b-a); }

  function spawnPulse(edge){
    var el = document.getElementById(edge.id);
    var clone = el.cloneNode(false);
    clone.removeAttribute('id');
    el.parentNode.insertBefore(clone, el.nextSibling);
    var dir = Math.random() < 0.5 ? 1 : -1; // 1=forward -1=reverse
    var speed = rand(0.4, 1.6); // px per frame
    var startPos = dir === 1 ? edge.len + 30 : -7;
    clone.setAttribute('opacity','1');
    return {el:clone, len:edge.len, dir:dir, pos:startPos, speed:speed, edge:edge};
  }

  // Seed initial pulses — 2-4 per edge, staggered
  edges.forEach(function(e,i){
    var count = Math.floor(rand(1,3));
    for(var j=0;j<count;j++){
      setTimeout(function(edge){
        pulses.push(spawnPulse(edge));
      }, rand(0, 3000), e);
    }
  });

  // Periodically change connections: fade some edges, brighten others
  var edgeEls = [];
  document.querySelectorAll('line').forEach(function(l){ edgeEls.push(l); });

  function shuffleConnections(){
    // Pick 30-50% of edges to dim, rest stay
    edgeEls.forEach(function(l){
      var base = parseFloat(l.getAttribute('opacity')) || 0.3;
      var target = Math.random() < 0.35 ? base * 0.25 : base;
      // Animate opacity change
      var cur = parseFloat(l.getAttribute('opacity'));
      var step = (target - cur) / 40;
      var frames = 0;
      function fade(){
        frames++;
        cur += step;
        l.setAttribute('opacity', Math.max(0.03, cur));
        if(frames < 40) requestAnimationFrame(fade);
      }
      fade();
    });
    setTimeout(shuffleConnections, rand(2500, 5000));
  }
  setTimeout(shuffleConnections, 2000);

  // Spawn replacement pulses randomly
  function maybeSpawn(){
    // Keep ~35-55 active pulses total
    if(pulses.length < 45){
      var e = edges[Math.floor(Math.random()*edges.length)];
      pulses.push(spawnPulse(e));
    }
    setTimeout(maybeSpawn, rand(200, 800));
  }
  setTimeout(maybeSpawn, 500);

  // Main animation loop
  function tick(){
    for(var i = pulses.length-1; i >= 0; i--){
      var p = pulses[i];
      p.pos -= p.dir * p.speed;
      p.el.setAttribute('stroke-dashoffset', p.pos);
      // Done when dot has fully left the path
      var done = p.dir === 1
        ? p.pos < -(7 + 10)
        : p.pos > p.len + 30 + 10;
      if(done){
        p.el.parentNode && p.el.parentNode.removeChild(p.el);
        pulses.splice(i,1);
      }
    }
    requestAnimationFrame(tick);
  }
  requestAnimationFrame(tick);
})();
